        "html[data-dib-theme=konpeito] .cv2-nl-warn,html[data-dib-theme=konpeito] .cv2-nl-chk2,html[data-dib-theme=konpeito] .cv2-dl-del{font-family:'Nunito',sans-serif;}",
        "#dia-closet-v2-root .cv2-fly-grid{display:flex;flex-wrap:wrap;gap:14px;justify-content:center;align-content:flex-start;}",
        /* card width override removed: cards are 135px (the canonical rule below), matching the homepage exactly */
        "body.cv2-closet{overflow:hidden !important;overflow-x:auto !important;height:100vh !important;}",
        "body.cv2-closet #dia-closet-v2-root{min-width:950px !important;}", /* true 3-column floor (lists 240 + flyout 465 + rail 208 + gaps); was 1080px, which out-muscled max-width (min-width wins in CSS) and froze the layout — narrow windows clipped the rail, wide ones got phantom margins */
        "body.cv2-closet #container.cv2-active{width:min(1980px,98vw) !important;max-width:min(1980px,98vw) !important;margin-left:auto !important;margin-right:auto !important;}", /* fluid: DTI hardcodes 1240px; grid spans 3 columns (floor) up to 7-8 on ultrawide so big windows aren't all gutter */
        /* ── Responsive closet: sidebars give way first, grid floors at 3 columns and grows to 6, header pill always viewport-centered ── */
        "body.cv2-closet #dia-closet-v2-root{position:relative !important;margin-left:auto !important;margin-right:auto !important;}",
        "#dia-closet-v2-root .cv2-lists{flex:0 0 340px !important;min-width:340px !important;}", /* fixed: any narrower and the two-column list masonry collapses into stretched single-column cards mid-drag */
        "#dia-closet-v2-root #cv2-flyout{min-width:478px !important;}", /* 3-column floor with rounding buffer — exactly 465 flapped between 2 and 3 columns under zoom */
        "#dia-closet-v2-root .cv2-rightrail{position:static !important;right:auto !important;top:auto !important;margin-top:26px !important;flex:0 0 208px !important;min-width:172px !important;}", /* was absolute right:-226px, hanging OUTSIDE the layout — fine at the old fixed width, overflowed the viewport once the root went fluid; in-flow it can never escape */
        "#dia-closet-v2-root .cv2-layout{justify-content:center !important;}",
        "#dia-closet-v2-root .cv2-navwrap{position:static !important;justify-content:center !important;min-height:62px !important;}", /* the absolute nav pill removed itself from flow and collapsed this wrap to 0px, letting the panel slide up underneath — reserve the row */
        "#dia-closet-v2-root #dia-hp-nav{position:absolute !important;left:50% !important;transform:translateX(-50%) !important;margin:0 !important;z-index:340 !important;width:max-content !important;max-width:none !important;}", /* anchored to the centered root; width:max-content because absolute+left:50% caps shrink-to-fit at HALF the containing block, which wrapped the pill into two lines at narrow widths */
        "html:has(body.cv2-closet){overflow:hidden !important;}",
        "#dia-closet-v2-root .cv2-fly-grid li.object.cv2-add-card{width:135px !important;max-width:135px !important;min-height:150px;display:flex;flex-direction:column;align-items:center;justify-content:center;gap:11px;border:2.5px solid transparent;background:radial-gradient(#ffd6e3 1.5px,transparent 2px) 0 0/18px 18px padding-box,radial-gradient(#cfe9d6 1.5px,transparent 2px) 9px 9px/18px 18px padding-box,radial-gradient(#cfe4f5 1.5px,transparent 2px) 0 9px/18px 18px padding-box,linear-gradient(#fffaf3,#fffaf3) padding-box,linear-gradient(135deg,#ffd1dc,#d3edd9 52%,#cfe4f5) border-box;border-radius:18px;box-shadow:none;cursor:pointer;transition:transform .15s,filter .15s;padding:0;}",
        "#dia-closet-v2-root .cv2-add-card:hover,#dia-closet-v2-root .cv2-add-card.cv2-add-open{transform:translateY(-3px) scale(1.02);filter:saturate(1.25);}",
        "#dia-closet-v2-root .cv2-add-card:hover .cv2-add-plus,#dia-closet-v2-root .cv2-add-card.cv2-add-open .cv2-add-plus{transform:scale(1.1) rotate(90deg);}",
        "#dia-closet-v2-root .cv2-add-plus{width:46px;height:46px;border-radius:50%;display:flex;align-items:center;justify-content:center;background:linear-gradient(160deg,#ffe0ea,#ffffff 52%,#dcf0e3);color:#cf8aa6;box-shadow:inset 0 2px 4px rgba(255,255,255,.75),0 3px 9px rgba(180,150,165,.26);transition:transform .2s ease;}",
