  // On first run, migrate any existing localStorage data across then clean it up.
  let dateCache = {};
  try {
    const _gmRaw = GM_getValue(DATE_CACHE_KEY, null);
    if (_gmRaw) {
      dateCache = JSON.parse(_gmRaw);
    } else {
      // One-time migration from localStorage → GM storage
      const _lsRaw = localStorage.getItem(DATE_CACHE_KEY);
      if (_lsRaw) {
        dateCache = JSON.parse(_lsRaw);
        GM_setValue(DATE_CACHE_KEY, _lsRaw);
        localStorage.removeItem(DATE_CACHE_KEY);
      }
    }
  } catch(_) {}
  const saveDateCache = () => { try { GM_setValue(DATE_CACHE_KEY, JSON.stringify(dateCache)); } catch(_) {} };
  const getDateFilter = () => { try { return JSON.parse(localStorage.getItem(DATE_FILTER_KEY) || 'null') || {}; } catch(_) { return {}; } };
  const setDateFilter = f => { try { localStorage.setItem(DATE_FILTER_KEY, f && f.mode ? JSON.stringify(f) : 'null'); } catch(_) {} };

  const FILTER_CHIP_DYEWORKS_KEY = 'neo_dti_filter_chip_dyeworks';
  const FILTER_CHIP_BABY_KEY = 'neo_dti_filter_chip_baby';
  const FILTER_CHIP_MUTANT_KEY = 'neo_dti_filter_chip_mutant';
  const TRADE_STATUS_KEY = 'neo_dti_trade_statuses';
  const OWNER_NOTES_KEY = 'neo_dti_owner_notes';
  const FAVORITE_OWNERS_KEY = 'neo_dti_favorite_owners';
  const CUSTOM_STATUS_OPTIONS_KEY = 'neo_dti_custom_status_options';
  const STATUS_ORDER_KEY = 'neo_dti_status_order';
  const STATUS_COLOR_THEMES = {
    green: { label: 'Good', dot: '#6ab89a' },
    yellow: { label: 'Neutral', dot: '#d9bd42' },
    red: { label: 'Bad', dot: '#d98278' }
  };
  const DIA_DATA_KEY = 'dti_import_apprentice_data_v1';

  // ── Shared Lebron values fetch — one request for the entire script lifetime ──
