          qtyEl.className = 'dtr-wl-step-qty';

          const plusBtn = document.createElement('button');
          plusBtn.className = 'dtr-wl-step-btn dtr-wl-step-plus';
          plusBtn.textContent = '+';
          plusBtn.type = 'button';

