        sourceCount: function(key){ try { return window.DTR_HAUL ? window.DTR_HAUL.sourceCount(key) : 0; } catch (_e) { return 0; } },
        emptyText: 'Click “Try On” on any item to stage it here for a quick try-on.',
        // 10.200: MINIMAL + EPHEMERAL. The right-hand list shows ONLY the current item — a single
