          if (e.target.closest('button') && !e.target.closest('.tryon-canvas-copy, .tryon-canvas-keepcust')) return;
          const els = ['dia-hp-tryon-panel', 'dia-hp-wl-panel', 'dtr-tophat', 'dia-tryon-picker-drawer']
            .map(id => document.getElementById(id))
            .filter(el => el && el.style.display !== 'none');
